"use client";

import { usePathname, useRouter } from "next/navigation";
import styles from "./BottomNav.module.css";
import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";

export default function BottomNav() {
    const { t } = useTranslation('common');
    const router = useRouter();
    const pathname = usePathname();
    const [activeTab, setActiveTab] = useState("/");

    const navItems = [
        { path: "/", icon: "??

/" },
        { path: "/explore", icon: "?뵇", label: t('common.explore_nav', { defaultValue: 'Explore' }), activeKey: "/explore" },
        { path: "/navigation", icon: "?뱧", label: t('common.today_nav', { defaultValue: 'Itinerary' }), activeKey: "/navigation" },
        { path: "/community", icon: "?뮠", label: t('common.community_nav', { defaultValue: 'Community' }), activeKey: "/community" },
        { path: "/my", icon: "?뫀", label: t('common.my_nav', { defaultValue: 'My Info' }), activeKey: "/my" },
    ];

    useEffect(() => {
        const matched = navItems.find(item => {
            if (item.activeKey === "/") return pathname === "/";
            return pathname.startsWith(item.activeKey);
        });
        setActiveTab(matched?.activeKey ?? "");
    }, [pathname]);

    // auth ?섏씠吏 諛?lang-test?먯꽌???④?
    if (pathname.startsWith("/auth") || pathname.startsWith("/lang-test")) return null;

    return (
        <nav className={styles.navBar}>
            {navItems.map((item) => {
                const isActive = activeTab === item.activeKey;
                return (
                    <div
                        key={item.path}
                        className={`${styles.navItem} ${isActive ? styles.active : ""}`}
                        onClick={() => router.push(item.path)}
                    >
                        {isActive && <div className={styles.indicator} />}
                        <span className={styles.navIcon}>{item.icon}</span>
                        <span className={styles.navLabel}>{item.label}</span>
                    </div>
                );
            })}
        </nav>
    );
}

