'use client';

import { useState, useEffect } from 'react';
import { changeLanguage } from '@/lib/i18n/client';
import styles from './LanguagePicker.module.css';

export interface LangOption {
    code: string;
    label: string;
    flag: string;
}

export const LANGUAGES: LangOption[] = [
    { code: 'ko', label: '?쒓뎅??, flag: '?눖?눟' },
    { code: 'en', label: 'English', flag: '?눣?눡' },
    { code: 'ja', label: '?ζ쑍沃?, flag: '?눓?눝' },
    { code: 'zh-CN', label: '嶸鵝볞릎??, flag: '?눊?눛' },
    { code: 'zh-TW', label: '濚곲쳱訝?뻼', flag: '?눑?눖' },
    { code: 'vi', label: 'Ti梳퓆g Vi沼뇍', flag: '?눤?눛' },
    { code: 'th', label: '仙꾝툠錫?, flag: '?눢?눑' },
    { code: 'id', label: 'Bahasa Indonesia', flag: '?눒?눍' },
    { code: 'ms', label: 'Bahasa Melayu', flag: '?눚?눧' },
];

// ?몄뼱肄붾뱶 ??i18n ??留ㅽ븨 (?ㅼ젣 吏?먰븯???ㅻ줈 ?쇱슦??
const LANG_MAP: Record<string, string> = {
    'ko': 'ko', 'en': 'en', 'ja': 'jp', 'zh-CN': 'cn', 'zh-TW': 'tw',
    'vi': 'vi', 'th': 'th', 'id': 'id', 'ms': 'ms'
};

function toI18nKey(code: string) {
    return LANG_MAP[code] ?? 'en';
}

import { useTranslation } from 'react-i18next';

interface LanguagePickerProps {
    compact?: boolean;
}

export default function LanguagePicker({ compact = false }: LanguagePickerProps) {
    const { t } = useTranslation('common');
    // Dropdown open state
    const [isOpen, setIsOpen] = useState(false);

    // Default to Korean
    const [current, setCurrent] = useState<LangOption>(LANGUAGES.find(l => l.code === 'ko') || LANGUAGES[14]);

    // load saved lang from localStorage
    useEffect(() => {
        const stored = localStorage.getItem('ktrip_lang');
        if (stored) {
            const found = LANGUAGES.find(l => toI18nKey(l.code) === stored || l.code === stored);
            if (found) setCurrent(found);
        } else {
            // Default is Korean as requested
            setCurrent(LANGUAGES.find(l => l.code === 'ko') || LANGUAGES[14]);
        }
    }, []);

    const handleSelect = (lang: LangOption) => {
        setCurrent(lang);
        setIsOpen(false);
        const i18nKey = toI18nKey(lang.code);
        changeLanguage(i18nKey);
    };

    return (
        <div className={styles.wrapper}>
            <button
                className={`${styles.trigger} ${compact ? styles.compact : ''}`}
                onClick={() => setIsOpen(v => !v)}
                title="Select Language"
            >
                <span className={styles.flag}>{current.flag}</span>
                {!compact && <span className={styles.langLabel}>{current.label}</span>}
                <span className={styles.chevron}>{isOpen ? '?? : '??}</span>
            </button>

            {isOpen && (
                <>
                    <div className={styles.backdrop} onClick={() => setIsOpen(false)} />
                    <div className={styles.dropdown}>
                        <div className={styles.dropdownHeader}>
                            <h2>{t('common.select_language', { defaultValue: 'Select Language' })}</h2>
                        </div>
                        <div className={styles.langList}>
                            {LANGUAGES.map(lang => (
                                <button
                                    key={lang.code}
                                    className={`${styles.langItem} ${current.code === lang.code ? styles.active : ''}`}
                                    onClick={() => handleSelect(lang)}
                                >
                                    <span className={styles.itemFlag}>{lang.flag}</span>
                                    <span className={styles.itemLabel}>{lang.label}</span>
                                </button>
                            ))}
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import dynamic from "next/dynamic";

const MapContainer = dynamic(
    () => import("react-leaflet").then((mod) => mod.MapContainer),
    { ssr: false }
);
const TileLayer = dynamic(
    () => import("react-leaflet").then((mod) => mod.TileLayer),
    { ssr: false }
);
const Marker = dynamic(
    () => import("react-leaflet").then((mod) => mod.Marker),
    { ssr: false }
);
const Popup = dynamic(
    () => import("react-leaflet").then((mod) => mod.Popup),
    { ssr: false }
);
const Polyline = dynamic(
    () => import("react-leaflet").then((mod) => mod.Polyline),
    { ssr: false }
);

interface MapProps {
    center: [number, number];
    zoom?: number;
    markers?: Array<{ position: [number, number]; popupText?: string }>;
    path?: [number, number][]; // Route coordinates
    height?: string;
}

export default function Map({ center, zoom = 13, markers = [], path = [], height = "35vh" }: MapProps) {
    const [isMounted, setIsMounted] = useState(false);

    useEffect(() => {
        // Inject leaflet CSS only in browser
        if (!document.getElementById('leaflet-css')) {
            const link = document.createElement('link');
            link.id = 'leaflet-css';
            link.rel = 'stylesheet';
            link.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css';
            document.head.appendChild(link);
        }
        import('leaflet').then((L) => {
            const iconUrl = 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon.png';
            const iconRetinaUrl = 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon-2x.png';
            const shadowUrl = 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-shadow.png';
            const DefaultIcon = L.icon({ iconRetinaUrl, iconUrl, shadowUrl, iconSize: [25, 41], iconAnchor: [12, 41], popupAnchor: [1, -34], shadowSize: [41, 41] });
            L.Marker.prototype.options.icon = DefaultIcon;
        });
        setIsMounted(true);
    }, []);

    if (!isMounted) {
        return <div style={{ height, background: "#222", display: "flex", alignItems: "center", justifyContent: "center", color: "#666" }}>Loading Map...</div>;
    }

    // Type assertion for LatLngExpression (Leaflet types can be tricky with dynamic imports)
    const centerPos: any = center;
    const pathPositions: any[] = path;

    return (
        <MapContainer
            center={centerPos}
            zoom={zoom}
            scrollWheelZoom={false}
            style={{ height, width: "100%", zIndex: 0 }}
        >
            <TileLayer
                attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>'
                url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png"
            />

            {markers.map((marker, idx) => (
                <Marker key={idx} position={marker.position as any}>
                    {marker.popupText && <Popup>{marker.popupText}</Popup>}
                </Marker>
            ))}

            {path.length > 0 && (
                <Polyline
                    positions={pathPositions}
                    pathOptions={{ color: '#3cb44a', weight: 4, opacity: 0.8 }}
                />
            )}
        </MapContainer>
    );
}

