        // Get current location
        navigator.geolocation.getCurrentPosition(
            async (position) => {
                const { latitude, longitude } = position.coords;

                try {
                    // Fetch weather data
                    const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current_weather=true`);
                    if (!res.ok) return;

                    const data = await res.json();
                    if (data.current_weather) {
                        const code = data.current_weather.weathercode;
                        let icon = '?뙟截?; // Default

                        if (code === 0) icon = '?截?; // Clear
                        else if (code >= 1 && code <= 3) icon = '??; // Partly cloudy
                        else if (code >= 45 && code <= 48) icon = '?뙧截?; // Fog
                        else if (code >= 51 && code <= 67) icon = '?뙢截?; // Rain
                        else if (code >= 71 && code <= 77) icon = '?꾬툘'; // Snow
                        else if (code >= 80 && code <= 82) icon = '?뙡截?; // Showers
                        else if (code >= 95) icon = '?덌툘'; // Thunderstorm

                        setWeatherData({
                            temp: Math.round(data.current_weather.temperature),
                            icon: icon
                        });
                    }
                } catch (err) {
                    // Silently ignore or warn so the Next.js error overlay is not triggered
                    console.warn("Failed to fetch weather data, skipping widget.");
                }
            },
            (error) => {
                console.warn("Error getting location", error);
            }
        );
    }, []);

    if (!weatherData) return null;

    return (
        <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '4px',
            fontSize: '11px',
            backgroundColor: 'var(--gray-100)',
            padding: '4px 10px',
            borderRadius: '20px',
            color: 'var(--foreground)',
            border: '1px solid var(--gray-200)',
            fontWeight: 600
        }}>
            <span>{weatherData.icon}</span>
            <span style={{ fontWeight: 600 }}>{weatherData.temp}째C</span>
        </div>
    );
}

